def assert_on_ramp_review_audit_is_clean() -> None:
    on_ramp_spanish = {
        spanish
        for _domain, pack in ON_RAMP_DOMAIN_PACKS
        for item in pack
        for _sentence_id, _accepted_id, spanish, _english in item["sentences"]
    }
    for review_type, audit in ON_RAMP_INDEPENDENT_REVIEW_AUDIT.items():
        rejected = sorted(on_ramp_spanish & audit["rejectedSpanish"])
        if rejected:
            raise ValueError(
                f"on-ramp pack includes {review_type} rejected item(s): {', '.join(rejected)}"
            )


assert_on_ramp_review_audit_is_clean()

