# --------------------------------------------------------------------------------------
# A tiny VETTED sample slice (the real build ingests Tatoeba/frequency lists; O1 picks the
# exact frequency list). Every row carries provenance. `authored` rows (e.g. accepted-answer
# variants) still require a human reviewer before REVIEWED.
# --------------------------------------------------------------------------------------
@dataclass
class Row:
    data: dict
    # provenance starts UNVETTED on ingest; stages promote it.
    source: str = "tatoeba"
    sourceId: str = ""
    license: str = "CC-BY-2.0-FR"
    vettingStatus: str = UNVETTED
    reviewedBy: str | None = None
    reviewedAt: int | None = None
    reviewEvidence: list[dict] = field(default_factory=list)


def row_table_id(table: str, row: Row) -> int:
    if table == "lexeme":
        return row.data["lexemeId"]
    if table == "sentence":
        return row.data["sentenceId"]
    if table == "accepted_answer":
        return row.data["acceptedAnswerId"]
    raise ValueError(f"unknown evidence table {table}")


def review_evidence_key(table: str, row: Row) -> str:
    return f"{table}:{row_table_id(table, row)}"


def review_evidence_content_payload(table: str, row: Row) -> dict:
    return {
        "table": table,
        "id": row_table_id(table, row),
        "source": row.source,
        "sourceId": row.sourceId,
        "license": row.license,
        "data": row.data,
    }


def review_evidence_content_hash(table: str, row: Row) -> str:
    payload = json.dumps(
        review_evidence_content_payload(table, row),
        sort_keys=True,
        ensure_ascii=False,
        separators=(",", ":"),
    )
    return "sha256:" + hashlib.sha256(payload.encode("utf-8")).hexdigest()


def review_evidence_cross_checks(table: str, row: Row) -> dict:
    checks = {"sourceId": row.sourceId}
    if table == "lexeme":
        checks.update({
            "text": row.data.get("lemma"),
            "english": row.data.get("englishGloss"),
            "cefrBand": row.data.get("cefrBand"),
        })
    elif table == "sentence":
        checks.update({
            "text": row.data.get("spanishText"),
            "english": row.data.get("englishText"),
        })
    elif table == "accepted_answer":
        checks.update({
            "text": row.data.get("answerText"),
            "sentenceId": row.data.get("sentenceId"),
            "direction": row.data.get("direction"),
        })
    else:
        raise ValueError(f"unknown evidence table {table}")
    return checks


def load_review_evidence_file(path: str, source_label: str | None = None) -> dict[str, dict]:
    source_label = source_label or os.path.basename(path)
    with open(path, encoding="utf-8") as f:
        payload = json.load(f)
    if payload.get("schemaVersion") != 1:
        raise ValueError(f"{source_label} must have schemaVersion 1")

    items: dict[str, dict] = {}
    for include in payload.get("includes", []):
        include_path = include
        if not os.path.isabs(include_path):
            include_path = os.path.join(os.path.dirname(path), include_path)
        included_items = load_review_evidence_file(include_path, include)
        for key, item in included_items.items():
            if key in items and items[key] != item:
                raise ValueError(f"conflicting review evidence for {key}")
            items[key] = item

    for key, item in payload.get("items", {}).items():
        if key in items and items[key] != item:
            raise ValueError(f"conflicting review evidence for {key}")
        item = dict(item)
        item["_evidenceSourceFile"] = source_label
        items[key] = item
    return items


def load_review_evidence_items(path: str = REVIEW_EVIDENCE_PATH) -> dict[str, dict]:
    return load_review_evidence_file(path)


def review_rationale_boilerplate_signature(rationale: str) -> str:
    def normalize_quoted(match: re.Match[str]) -> str:
        quoted = match.group(0)
        inner = quoted[1:-1]
        if len(inner) <= 40:
            return quoted
        return f"{quoted[0]}<quoted>{quoted[-1]}"

    signature = rationale.lower()
    signature = re.sub(r"'[^']*'", normalize_quoted, signature)
    signature = re.sub(r'"[^"]*"', normalize_quoted, signature)
    signature = re.sub(r"\b(?:lexeme|sentence|accepted_answer):\d+\b", "<stable-key>", signature)
    signature = re.sub(r"\bsha256:[0-9a-f]+\b", "<hash>", signature)
    signature = re.sub(r"\b\d+\b", "<number>", signature)
    signature = re.sub(r"\s+", " ", signature).strip()
    return signature


def validate_review_evidence_catalog(items: dict[str, dict]) -> None:
    allowed_dimensions = {
        AUTO_REVIEW_SPANISH,
        AUTO_REVIEW_PEDAGOGY,
        AUTO_REVIEW_AUTHENTICITY,
        AUTO_REVIEW_DIALECT,
    }
    allowed_bases = {EVIDENCE_BASIS_PER_ITEM, EVIDENCE_BASIS_LEGACY}
    max_reused_per_item_rationale = 5
    failures: list[str] = []
    per_item_rationales_by_dimension: dict[str, list[tuple[str, str]]] = {}
    per_item_signatures_by_dimension: dict[str, list[tuple[str, str]]] = {}
    for key, item in items.items():
        if item.get("stableKey") != key:
            failures.append(f"{key} stableKey mismatch")
        dimensions = item.get("dimensions")
        if not isinstance(dimensions, dict):
            failures.append(f"{key} dimensions must be an object")
            continue
        unknown_dimensions = sorted(set(dimensions) - allowed_dimensions)
        if unknown_dimensions:
            failures.append(f"{key} has unknown review dimension(s): {', '.join(unknown_dimensions)}")
        for review_type, evidence in dimensions.items():
            basis = evidence.get("evidenceBasis")
            if basis not in allowed_bases:
                failures.append(f"{key} {review_type} has invalid evidenceBasis {basis!r}")
            if basis == EVIDENCE_BASIS_LEGACY and item.get("_evidenceSourceFile") != "review_evidence_legacy.json":
                failures.append(f"{key} {review_type} uses legacy_pack_attestation outside review_evidence_legacy.json")
            if basis == EVIDENCE_BASIS_PER_ITEM:
                rationale = (evidence.get("rationale") or "").strip()
                if not rationale:
                    failures.append(f"{key} {review_type} per_item_review missing rationale")
                else:
                    per_item_rationales_by_dimension.setdefault(review_type, []).append((rationale, key))
                    per_item_signatures_by_dimension.setdefault(review_type, []).append((
                        review_rationale_boilerplate_signature(rationale),
                        key,
                    ))
    for review_type, rationale_entries in sorted(per_item_rationales_by_dimension.items()):
        repeated: dict[str, list[str]] = {}
        for rationale, key in rationale_entries:
            repeated.setdefault(rationale, []).append(key)
        for rationale, keys in sorted(repeated.items(), key=lambda entry: (-len(entry[1]), entry[0])):
            if len(keys) > max_reused_per_item_rationale:
                failures.append(
                    f"{review_type} per_item_review rationale reused {len(keys)} times "
                    f"(max {max_reused_per_item_rationale}); first keys: {', '.join(keys[:5])}"
                )
    for review_type, signature_entries in sorted(per_item_signatures_by_dimension.items()):
        repeated: dict[str, list[str]] = {}
        for signature, key in signature_entries:
            repeated.setdefault(signature, []).append(key)
        for signature, keys in sorted(repeated.items(), key=lambda entry: (-len(entry[1]), entry[0])):
            if len(keys) > max_reused_per_item_rationale:
                failures.append(
                    f"{review_type} per_item_review rationale boilerplate pattern reused {len(keys)} times "
                    f"(max {max_reused_per_item_rationale}); first keys: {', '.join(keys[:5])}"
                )
    legacy_count = sum(1 for item in items.values() if item.get("_evidenceSourceFile") == "review_evidence_legacy.json")
    if legacy_count != FROZEN_LEGACY_REVIEW_EVIDENCE_ITEM_COUNT:
        failures.append(
            f"review_evidence_legacy.json item count {legacy_count} != "
            f"frozen count {FROZEN_LEGACY_REVIEW_EVIDENCE_ITEM_COUNT}"
        )
    if failures:
        raise SystemExit("INVALID REVIEW EVIDENCE:\n  " + "\n  ".join(failures))


REVIEW_EVIDENCE_ITEMS = load_review_evidence_items()
validate_review_evidence_catalog(REVIEW_EVIDENCE_ITEMS)


def validate_explicit_review_evidence(table: str, row: Row, required: set[str]) -> tuple[list[dict], list[str]]:
    key = review_evidence_key(table, row)
    item = REVIEW_EVIDENCE_ITEMS.get(key)
    failures: list[str] = []
    if item is None:
        return [], [f"{key} is missing explicit review evidence"]

    if item.get("itemType") != table:
        failures.append(f"{key} itemType mismatch: {item.get('itemType')!r} != {table!r}")
    expected_hash = review_evidence_content_hash(table, row)
    if item.get("contentHash") != expected_hash:
        failures.append(f"{key} has stale or mismatched content hash")
    expected_checks = review_evidence_cross_checks(table, row)
    actual_checks = item.get("crossChecks") or {}
    for check_key, expected_value in expected_checks.items():
        if actual_checks.get(check_key) != expected_value:
            failures.append(
                f"{key} cross-check {check_key} mismatch: "
                f"{actual_checks.get(check_key)!r} != {expected_value!r}"
            )

    dimensions = item.get("dimensions") or {}
    approved_records: list[dict] = []
    for review_type in sorted(required):
        evidence = dimensions.get(review_type)
        if evidence is None:
            failures.append(f"{key} missing evidence for {review_type}")
            continue
        if evidence.get("verdict") != APPROVED_VERDICT:
            failures.append(f"{key} {review_type} verdict is {evidence.get('verdict')!r}, not APPROVED")
        if not evidence.get("reviewer"):
            failures.append(f"{key} {review_type} missing reviewer")
        if not evidence.get("reviewedAt"):
            failures.append(f"{key} {review_type} missing reviewedAt")
        if evidence.get("evidenceBasis") == EVIDENCE_BASIS_LEGACY and item.get("_evidenceSourceFile") != "review_evidence_legacy.json":
            failures.append(f"{key} {review_type} legacy_pack_attestation is not allowed for new evidence")
        approved_records.append({
            "reviewType": review_type,
            "reviewer": evidence.get("reviewer"),
            "reviewedAt": evidence.get("reviewedAt"),
            "decision": evidence.get("verdict"),
            "notes": evidence.get("rationale", ""),
            "evidenceBasis": evidence.get("evidenceBasis"),
            "evidenceSource": evidence.get("source"),
            "contentHash": item.get("contentHash"),
            "evidenceSourceFile": item.get("_evidenceSourceFile"),
        })

    reviewers = {
        record.get("reviewer")
        for record in approved_records
        if record.get("decision") == APPROVED_VERDICT and record.get("reviewer")
    }
    if len(reviewers) < len(required):
        failures.append(f"{key} lacks distinct reviewer identities for required dimensions")
    return approved_records, failures


def has_explicit_review_evidence(table: str, row: Row, required: set[str]) -> bool:
    _records, failures = validate_explicit_review_evidence(table, row, required)
    return not failures


def register_per_item_review_evidence(table: str, row: Row, review_types: set[str], rationale: str) -> None:
    key = review_evidence_key(table, row)
    REVIEW_EVIDENCE_ITEMS[key] = {
        "itemType": table,
        "stableKey": key,
        "contentHash": review_evidence_content_hash(table, row),
        "crossChecks": review_evidence_cross_checks(table, row),
        "_evidenceSourceFile": "in_memory_fixture",
        "dimensions": {
            review_type: {
                "verdict": APPROVED_VERDICT,
                "reviewer": AUTO_REVIEW_REVIEWERS[review_type],
                "reviewedAt": AUTO_REVIEW_TS,
                "rationale": rationale,
                "evidenceBasis": EVIDENCE_BASIS_PER_ITEM,
                "source": "in-memory test fixture",
            }
            for review_type in review_types
        },
    }


def append_ai_accelerated_pack(pack, pack_slug: str, exercise_id: int,
                               lexemes, sentences, accepted, sentence_lexeme, exercises,
                               lexeme_source: str = "wiktionary",
                               lexeme_license: str = "CC-BY-SA-3.0",
                               lexeme_vetting_status: str = UNVETTED) -> int:
    for item in pack:
        lexeme_id = item["lexemeId"]
        lexeme_data = {
            "lexemeId": lexeme_id,
            "lemma": item["lemma"],
            "pos": item["pos"],
            "gender": item["gender"],
            "englishGloss": item["englishGloss"],
            "frequencyRank": item["frequencyRank"],
            "cefrBand": item["cefrBand"],
            "difficultyPrior": item["difficultyPrior"],
        }
        if item.get("phraseCefrRubric"):
            lexeme_data["phraseCefrRubric"] = item["phraseCefrRubric"]
            lexeme_data[INDEPENDENT_REVIEW_REQUIRED_FIELD] = True
        lexeme_source_id = item["lemma"]
        if lexeme_source == AI_DRAFT_SOURCE:
            lexeme_source_id = f"ai_draft:{pack_slug}-{item['lemma']}-lexeme"
        lexemes.append(Row(
            lexeme_data,
            source=lexeme_source,
            sourceId=lexeme_source_id,
            license=lexeme_license,
            vettingStatus=lexeme_vetting_status,
        ))

        sentence_ids = []
        for sentence_id, accepted_id, spanish, english in item["sentences"]:
            sentence_ids.append(sentence_id)
            sentences.append(Row({
                "sentenceId": sentence_id,
                "spanishText": spanish,
                "englishText": english,
            }, source=AI_DRAFT_SOURCE,
                sourceId=f"ai_draft:{pack_slug}-{item['lemma']}-{len(sentence_ids)}",
                license="proprietary", vettingStatus=AI_DRAFT))
            accepted.append(Row({
                "acceptedAnswerId": accepted_id,
                "sentenceId": sentence_id,
                "direction": "ES_TO_EN",
                "answerText": normalize_answer(english),
            }, source=AI_DRAFT_SOURCE,
                sourceId=f"ai_draft:{pack_slug}-{item['lemma']}-{len(sentence_ids)}-answer",
                license="proprietary", vettingStatus=AI_DRAFT))
            sentence_lexeme.append((sentence_id, lexeme_id))

        if not sentence_ids:
            raise ValueError(f"{item['lemma']} must define at least one reviewed sentence")
        exercises.append({"exerciseId": exercise_id, "nodeId": 1, "sentenceId": sentence_ids[0],
                          "type": "TYPED_TRANSLATION", "direction": "ES_TO_EN",
                          "targetItemId": lexeme_id, "targetItemType": "LEXEME", "promptHint": None})
        exercise_id += 1
        if len(sentence_ids) > 1:
            exercises.append({"exerciseId": exercise_id, "nodeId": 1, "sentenceId": sentence_ids[1],
                              "type": "WORD_BANK", "direction": "ES_TO_EN",
                              "targetItemId": lexeme_id, "targetItemType": "LEXEME", "promptHint": None})
            exercise_id += 1
    return exercise_id


def has_phrase_review_ledger_entry(row: Row) -> bool:
    if not row.data.get("phraseCefrRubric"):
        return False
    _records, failures = validate_explicit_review_evidence(
        "lexeme",
        row,
        {AUTO_REVIEW_SPANISH, AUTO_REVIEW_AUTHENTICITY, AUTO_REVIEW_DIALECT},
    )
    if failures:
        raise SystemExit(
            "CORRUPT REVIEW EVIDENCE for generated phrase/chunk content:\n  "
            + "\n  ".join(failures)
        )
    return True


def generated_sentence_has_blocked_content(row: Row) -> bool:
    if row.source != AI_DRAFT_SOURCE or "spanishText" not in row.data:
        return False
    spanish = row.data["spanishText"]
    if re.search(r"\baparece\s+aqui\b", normalize_signal_text(spanish)):
        return True
    return bool(set(phrase_tokens(spanish)) & set(PENINSULAR_OR_NON_NEUTRAL_LATAM_TERMS))


def prune_unreviewed_phrase_content(lexemes, sentences, accepted, sentence_lexeme, exercises):
    kept_lexeme_ids = {
        row.data["lexemeId"]
        for row in lexemes
        if (
            not (set(phrase_tokens(row.data.get("lemma"))) & set(PENINSULAR_OR_NON_NEUTRAL_LATAM_TERMS))
            and (not is_phrase_or_chunk_lexeme(row) or has_phrase_review_ledger_entry(row))
        )
    }
    lexemes[:] = [row for row in lexemes if row.data["lexemeId"] in kept_lexeme_ids]

    sentence_lexeme[:] = [
        (sentence_id, lexeme_id)
        for sentence_id, lexeme_id in sentence_lexeme
        if lexeme_id in kept_lexeme_ids
    ]
    kept_sentence_ids = {sentence_id for sentence_id, _lexeme_id in sentence_lexeme}
    reviewed_phrase_lexeme_ids = {
        row.data["lexemeId"]
        for row in lexemes
        if row.data["lexemeId"] in kept_lexeme_ids
        and is_phrase_or_chunk_lexeme(row)
        and bool(row.data.get("phraseCefrRubric"))
    }
    lexeme_ids_by_sentence: dict[int, set[int]] = {}
    for sentence_id, lexeme_id in sentence_lexeme:
        lexeme_ids_by_sentence.setdefault(sentence_id, set()).add(lexeme_id)
    blocked_sentence_ids = {
        row.data["sentenceId"]
        for row in sentences
        if (
            row.data["sentenceId"] in kept_sentence_ids
            and generated_sentence_has_blocked_content(row)
            and not (lexeme_ids_by_sentence.get(row.data["sentenceId"], set()) & reviewed_phrase_lexeme_ids)
        )
    }
    if blocked_sentence_ids:
        kept_sentence_ids -= blocked_sentence_ids
        sentence_lexeme[:] = [
            (sentence_id, lexeme_id)
            for sentence_id, lexeme_id in sentence_lexeme
            if sentence_id in kept_sentence_ids
        ]
    sentences[:] = [row for row in sentences if row.data["sentenceId"] in kept_sentence_ids]
    accepted[:] = [row for row in accepted if row.data["sentenceId"] in kept_sentence_ids]
    exercises[:] = [
        exercise for exercise in exercises
        if (
            exercise["sentenceId"] in kept_sentence_ids
            and (
                exercise["targetItemType"] != "LEXEME"
                or exercise["targetItemId"] in kept_lexeme_ids
            )
        )
    ]


def on_ramp_order_by_lexeme_id() -> dict[int, int]:
    ordered = {}
    for _domain, pack in ON_RAMP_DOMAIN_PACKS:
        for item in pack:
            ordered[item["lexemeId"]] = len(ordered)
    return ordered


def split_evenly(items: list[Row], part_count: int) -> list[list[Row]]:
    if part_count <= 0:
        return []
    base_size, remainder = divmod(len(items), part_count)
    parts = []
    cursor = 0
    for index in range(part_count):
        size = base_size + (1 if index < remainder else 0)
        parts.append(items[cursor:cursor + size])
        cursor += size
    return parts


def chunked(items: list[Row], size: int) -> list[list[Row]]:
    return [items[index:index + size] for index in range(0, len(items), size)]


def sequence_target_sort_key(row: Row) -> tuple:
    data = row.data
    on_ramp_order = on_ramp_order_by_lexeme_id().get(data["lexemeId"])
    return (
        CEFR_ORDER.index(data["cefrBand"]) if data["cefrBand"] in CEFR_ORDER else len(CEFR_ORDER),
        0 if on_ramp_order is not None else 1,
        on_ramp_order if on_ramp_order is not None else math.inf,
        data["frequencyRank"],
        data["lexemeId"],
    )


def build_sequencing_plan(lexemes: list[Row]) -> dict:
    ordered_targets = sorted(lexemes, key=sequence_target_sort_key)
    by_cefr = {cefr_band: [] for cefr_band in CEFR_ORDER}
    for row in ordered_targets:
        by_cefr.setdefault(row.data["cefrBand"], []).append(row)

    nodes: list[tuple[int, str, int]] = []
    target_intro_node: dict[int, int] = {}
    target_review_node: dict[int, int] = {}
    unit_metadata: list[dict] = []
    node_id = 1

    for cefr_band in CEFR_ORDER:
        targets = by_cefr.get(cefr_band, [])
        if not targets:
            continue
        unit_count = SEQUENCING_UNIT_COUNTS.get(
            cefr_band,
            max(1, math.ceil(len(targets) / SEQUENCING_MAX_NEW_TARGETS_PER_NODE)),
        )
        target_chunks = chunked(targets, SEQUENCING_MAX_NEW_TARGETS_PER_NODE)
        for unit_index, unit_chunks in enumerate(split_evenly(target_chunks, unit_count), start=1):
            if not unit_chunks:
                continue
            unit_node_ids = []
            unit_targets = [row for target_chunk in unit_chunks for row in target_chunk]
            for lesson_index, target_chunk in enumerate(unit_chunks, start=1):
                title = f"{cefr_band} Unit {unit_index}.{lesson_index}"
                nodes.append((node_id, title, len(nodes)))
                unit_node_ids.append(node_id)
                for row in target_chunk:
                    target_intro_node[row.data["lexemeId"]] = node_id
                node_id += 1

            checkpoint_id = node_id
            nodes.append((checkpoint_id, f"{cefr_band} Unit {unit_index} Review", len(nodes)))
            for row in unit_targets:
                target_review_node[row.data["lexemeId"]] = checkpoint_id
            unit_node_ids.append(checkpoint_id)
            unit_metadata.append({
                "cefrBand": cefr_band,
                "unit": unit_index,
                "targetCount": len(unit_targets),
                "nodeIds": unit_node_ids,
                "checkpointNodeId": checkpoint_id,
            })
            node_id += 1

    return {
        "nodes": nodes,
        "targetIntroNode": target_intro_node,
        "targetReviewNode": target_review_node,
        "unitMetadata": unit_metadata,
    }


def apply_sequencing_plan(lexemes: list[Row], exercises: list[dict]) -> list[tuple[int, str, int]]:
    plan = build_sequencing_plan(lexemes)
    exercises_by_target: dict[int, list[dict]] = {}
    for exercise in exercises:
        if exercise["targetItemType"] == "LEXEME":
            exercises_by_target.setdefault(exercise["targetItemId"], []).append(exercise)

    for target_id, target_exercises in exercises_by_target.items():
        intro_node = plan["targetIntroNode"].get(target_id)
        if intro_node is None:
            continue
        review_node = plan["targetReviewNode"].get(target_id, intro_node)
        for index, exercise in enumerate(sorted(target_exercises, key=lambda row: row["exerciseId"])):
            exercise["nodeId"] = intro_node if index == 0 else review_node
    return plan["nodes"]


def node_cefr_band(title: str) -> str:
    first = title.split(" ", 1)[0]
    return first if first in CEFR_ORDER else "unknown"


def validate_sequencing(lexemes: list[Row], exercises: list[dict],
                        nodes: list[tuple[int, str, int]]) -> dict:
    node_by_id = {node_id: {"nodeId": node_id, "title": title, "displayOrder": display_order}
                  for node_id, title, display_order in nodes}
    order_by_node_id = {node_id: display_order for node_id, _title, display_order in nodes}
    lexeme_by_id = {row.data["lexemeId"]: row for row in lexemes}
    target_ids = set(lexeme_by_id)
    assigned_intro_by_target = {
        target_id: node_id
        for target_id, node_id in build_sequencing_plan(lexemes)["targetIntroNode"].items()
        if target_id in target_ids
    }
    exercises_by_node: dict[int, list[dict]] = {}
    for exercise in exercises:
        exercises_by_node.setdefault(exercise["nodeId"], []).append(exercise)

    targets_with_intro_exercise = {
        exercise["targetItemId"]
        for exercise in exercises
        if (
            exercise["targetItemType"] == "LEXEME"
            and exercise["targetItemId"] in assigned_intro_by_target
            and exercise["nodeId"] == assigned_intro_by_target[exercise["targetItemId"]]
        )
    }

    new_targets_by_node: dict[int, list[int]] = {node_id: [] for node_id in node_by_id}
    for target_id, node_id in assigned_intro_by_target.items():
        new_targets_by_node.setdefault(node_id, []).append(target_id)

    missing_intro = sorted(target_ids - targets_with_intro_exercise)
    overfull_intro_nodes = [
        {
            **node_by_id[node_id],
            "newTargetCount": len(target_ids_for_node),
        }
        for node_id, target_ids_for_node in sorted(new_targets_by_node.items())
        if len(target_ids_for_node) > SEQUENCING_MAX_NEW_TARGETS_PER_NODE
    ]

    use_before_intro = []
    recycled_floor_failures = []
    node_counts = []
    introduced_so_far: set[int] = set()
    for node_id, title, _display_order in sorted(nodes, key=lambda row: row[2]):
        node_exercises = [
            exercise for exercise in exercises_by_node.get(node_id, [])
            if exercise["targetItemType"] == "LEXEME" and exercise["targetItemId"] in target_ids
        ]
        new_targets = set(new_targets_by_node.get(node_id, []))
        recycled_count = 0
        target_exercise_count = 0
        for exercise in node_exercises:
            target_id = exercise["targetItemId"]
            target_exercise_count += 1
            intro_node_id = assigned_intro_by_target.get(target_id)
            intro_order = order_by_node_id.get(intro_node_id) if intro_node_id is not None else None
            if intro_order is None or order_by_node_id[node_id] < intro_order:
                use_before_intro.append({
                    "exerciseId": exercise["exerciseId"],
                    "nodeId": node_id,
                    "targetItemId": target_id,
                    "firstIntroductionNode": intro_node_id,
                })
            if target_id in introduced_so_far:
                recycled_count += 1

        recycle_ratio = recycled_count / target_exercise_count if target_exercise_count else 1.0
        if not new_targets and target_exercise_count and recycle_ratio < SEQUENCING_RECYCLE_FLOOR:
            recycled_floor_failures.append({
                **node_by_id[node_id],
                "recycleRatio": recycle_ratio,
                "targetExerciseCount": target_exercise_count,
            })
        node_counts.append({
            **node_by_id[node_id],
            "cefrBand": node_cefr_band(title),
            "newTargetCount": len(new_targets),
            "targetExerciseCount": target_exercise_count,
            "recycledTargetExerciseCount": recycled_count,
            "recycleRatio": recycle_ratio,
        })
        introduced_so_far.update(new_targets)

    on_ramp_ids = set(on_ramp_order_by_lexeme_id()) & target_ids
    missing_on_ramp = sorted(on_ramp_ids - targets_with_intro_exercise)
    first_intro_by_cefr = count_by(
        lexeme_by_id[target_id].data["cefrBand"]
        for target_id in targets_with_intro_exercise
    )
    nodes_by_cefr = count_by(node_cefr_band(title) for _node_id, title, _display_order in nodes)
    checkpoint_nodes = [entry for entry in node_counts if entry["newTargetCount"] == 0]
    failures = {
        "targetsMissingFirstIntroduction": missing_intro,
        "usesBeforeIntroduction": use_before_intro,
        "introNodesOverTargetCap": overfull_intro_nodes,
        "nonIntroNodesBelowRecycleFloor": recycled_floor_failures,
        "onRampTargetsMissingIntroduction": missing_on_ramp,
    }
    return {
        "status": "failed" if any(failures.values()) else "passed",
        "constraints": {
            "maxNewTargetsPerIntroNode": SEQUENCING_MAX_NEW_TARGETS_PER_NODE,
            "minimumRecycleRatioForNonIntroNodes": SEQUENCING_RECYCLE_FLOOR,
            "unitCounts": SEQUENCING_UNIT_COUNTS,
        },
        "summary": {
            "targetCount": len(target_ids),
            "targetsWithFirstIntroduction": len(targets_with_intro_exercise),
            "nodeCount": len(nodes),
            "introNodeCount": sum(1 for entry in node_counts if entry["newTargetCount"] > 0),
            "checkpointNodeCount": len(checkpoint_nodes),
            "maxNewTargetsInIntroNode": max((entry["newTargetCount"] for entry in node_counts), default=0),
            "minRecycleRatioInNonIntroNode": min(
                (entry["recycleRatio"] for entry in checkpoint_nodes if entry["targetExerciseCount"]),
                default=1.0,
            ),
        },
        "counts": {
            "firstIntroductionsByCefrBand": dict(sorted(first_intro_by_cefr.items())),
            "nodesByCefrBand": dict(sorted(nodes_by_cefr.items())),
            "nodesByKind": {
                "intro": sum(1 for entry in node_counts if entry["newTargetCount"] > 0),
                "checkpoint": len(checkpoint_nodes),
            },
        },
        "firstIntroductionNodeByTarget": {
            str(target_id): assigned_intro_by_target[target_id]
            for target_id in sorted(targets_with_intro_exercise)
        },
        "nodeCounts": node_counts,
        "failures": failures,
    }


def write_sequencing_report(out_dir, lexemes, exercises, nodes):
    report = validate_sequencing(lexemes, exercises, nodes)
    path = os.path.join(out_dir, "sequencing_report.json")
    with open(path, "w") as f:
        json.dump(report, f, indent=2)
    return report


def enforce_sequencing(report: dict) -> None:
    if report["status"] == "passed":
        return
    failures = []
    for key, value in report["failures"].items():
        if value:
            failures.append(f"{key}: {len(value)}")
    sys.stderr.write("SEQUENCING VALIDATION FAILED:\n  " + "\n  ".join(failures) + "\n")
    raise SystemExit(5)


