        (AI_ACCELERATED_PACK_A2_047_REASONS_PROOFS_NOTICES_DEADLINES, "a2-047-reasons-proofs-notices-deadlines"),
        (AI_ACCELERATED_PACK_A2_048_LOCATIONS_DIRECTIONS_CONTACTS, "a2-048-locations-directions-contacts"),
